    def _update_file_header(self):
        header = bytearray(_HEADER_WITH_CRC_SIZE)

        # Header size
        header[0] = _HEADER_WITH_CRC_SIZE

        # Protocol version (2.0 => 0x20)
        header[1] = 0x20

        # Profile version
