        struct.pack_into('<I', header, 4, data_size)

        # Data type ".FIT"
        header[8] = 0x2E
        header[9] = 0x46
        header[10] = 0x49
        header[11] = 0x54

        # Header CRC
        crc = CrcCalculator.calculate_crc(header, 0, _HEADER_WITHOUT_CRC_SIZE)
        struct.pack_into('<H', header, 12, crc)

        self._output_stream.set_bytes(header, 0)

